package main

import (
	"fmt"
	"sync"
)

type Account struct {
	Balance int64
}

func (a *Account) Deposit(amount int64) {
	a.Balance += amount
}

func (a *Account) Withdraw(amount int64) error {
	if a.Balance < amount {
		return fmt.Errorf("insufficient balance")
	}
	a.Balance -= amount
	return nil
}

var accounts = make(map[string]*Account)
var mu sync.Mutex

func checkBalance(account string, amount int64) bool {
	mu.Lock()
	defer mu.Unlock()

	account, ok := accounts[account]
	if !ok {
		return false
	}
	return account.Balance >= amount
}

func updateAccount(account string, amount int64, op func(*Account)) error {
	mu.Lock()
	defer mu.Unlock()

	account, ok := accounts[account]
	if !ok {
		return fmt.Errorf("account not found")
	}
	op(account)
	return nil
}

func processTransaction(account string, amount int64) error {
	if checkBalance(account, amount) {
		updateAccount(account, amount, func(a *Account) {
			a.Deposit(amount)
		})
	} else {
		return fmt.Errorf("insufficient balance")
	}
	return nil
}

func main() {
	go processTransaction("account1", 100)
	go processTransaction("account2", 50)

	var wg sync.WaitGroup
	wg.Add(2)

	done := make(chan bool, 2)
	for i := 0; i < 2; i++ {
		go func() {
			defer wg.Done()
			if err := processTransaction("account1", 100); err != nil {
				fmt.Println(err)
			}
			done <- true
		}()
	}

	wg.Wait()
	close(done)

	for _, ok := range done {
		if !ok {
			fmt.Println("Error processing transaction")
		}
	}
}